import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import api from '../../services/api';
import '../../styles/storekeeper/storekeeper-imports.css';

const StorekeeperImports = () => {
  const { user } = useAuth();
  const [imports, setImports] = useState([]);
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showForm, setShowForm] = useState(false);

  const [filters, setFilters] = useState({
    productId: '',
    startDate: '',
    endDate: '',
  });

  const [formData, setFormData] = useState({
    productId: '',
    quantity: '',
    unitPrice: '',
    note: '',
    importDate: new Date().toISOString().split('T')[0],
  });

  useEffect(() => {
    loadImports();
    loadProducts();
  }, []);

  const loadImports = async () => {
    try {
      setLoading(true);
      setError(null);
      const params = new URLSearchParams();
      
      if (filters.productId) params.append('productId', filters.productId);
      if (filters.startDate) params.append('startDate', filters.startDate);
      if (filters.endDate) params.append('endDate', filters.endDate);

      const response = await api.get(`/inventory/imports?${params}`);
      setImports(response.data.data || []);
    } catch (err) {
      setError('Lỗi tải dữ liệu nhập kho');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const loadProducts = async () => {
    try {
      const response = await api.get('/inventory/products');
      setProducts(response.data.data || []);
    } catch (err) {
      console.error('Lỗi tải sản phẩm:', err);
    }
  };

  const handleFilterChange = (e) => {
    const { name, value } = e.target;
    setFilters(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleFilterSubmit = (e) => {
    e.preventDefault();
    loadImports();
  };

  const handleFormChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (!formData.productId || !formData.quantity || formData.unitPrice === '') {
        setError('Vui lòng điền đầy đủ thông tin: sản phẩm, số lượng, và giá');
        return;
      }

      const payload = {
        productId: parseInt(formData.productId),
        quantity: parseFloat(formData.quantity),
        unitPrice: parseFloat(formData.unitPrice),
        note: formData.note || null,
        importDate: formData.importDate,
      };

      const response = await api.post('/inventory/imports', payload);
      
      if (response.data.success) {
        setFormData({
          productId: '',
          quantity: '',
          unitPrice: '',
          note: '',
          importDate: new Date().toISOString().split('T')[0],
        });
        setShowForm(false);
        setError(null);
        loadImports();
      }
    } catch (err) {
      setError('Lỗi tạo phiếu nhập kho: ' + (err.response?.data?.message || err.message));
      console.error(err);
    }
  };

  const getProductName = (productId) => {
    const product = products.find(p => p.product_id === productId);
    return product ? product.product_name : 'N/A';
  };

  const getProductCode = (productId) => {
    const product = products.find(p => p.product_id === productId);
    return product ? product.product_code : 'N/A';
  };

  const getProductUnit = (productId) => {
    const product = products.find(p => p.product_id === productId);
    return product ? product.unit : 'N/A';
  };

  if (loading) {
    return (
      <div className="storekeeper-imports-container">
        <div className="loading-spinner">Đang tải...</div>
      </div>
    );
  }

  return (
    <div className="storekeeper-imports-container">
      <div className="storekeeper-imports-header">
        <h2>📥 Nhập Kho</h2>
        <button 
          className="btn-primary"
          onClick={() => setShowForm(!showForm)}
        >
          {showForm ? '✕ Đóng' : '➕ Nhập Kho Mới'}
        </button>
      </div>

      {error && <div className="alert alert-error">{error}</div>}

      {showForm && (
        <div className="storekeeper-imports__form-container">
          <form onSubmit={handleSubmit} className="storekeeper-imports__form">
            <h3>Tạo Phiếu Nhập Kho</h3>
            
            <div className="storekeeper-imports__form-row">
              <div className="form-group">
                <label>Sản phẩm *</label>
                <select
                  name="productId"
                  value={formData.productId}
                  onChange={handleFormChange}
                  className="form-input"
                  required
                >
                  <option value="">-- Chọn sản phẩm --</option>
                  {products.map(p => (
                    <option key={p.product_id} value={p.product_id}>
                      {p.product_code} - {p.product_name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label>Ngày Nhập *</label>
                <input
                  type="date"
                  name="importDate"
                  value={formData.importDate}
                  onChange={handleFormChange}
                  className="form-input"
                  required
                />
              </div>
            </div>

            <div className="storekeeper-imports__form-row">
              <div className="form-group">
                <label>Số Lượng *</label>
                <input
                  type="number"
                  name="quantity"
                  value={formData.quantity}
                  onChange={handleFormChange}
                  placeholder="VD: 100"
                  step="0.01"
                  className="form-input"
                  required
                />
              </div>

              <div className="form-group">
                <label>Đơn Giá *</label>
                <input
                  type="number"
                  name="unitPrice"
                  value={formData.unitPrice}
                  onChange={handleFormChange}
                  placeholder="VD: 50000"
                  step="0.01"
                  className="form-input"
                  required
                />
              </div>
            </div>

            <div className="form-group">
              <label>Ghi Chú</label>
              <textarea
                name="note"
                value={formData.note}
                onChange={handleFormChange}
                placeholder="Nhập ghi chú thêm (tùy chọn)"
                className="form-input"
                rows="3"
              />
            </div>

            <div className="storekeeper-imports__form-actions">
              <button type="submit" className="btn-primary">
                💾 Lưu Nhập Kho
              </button>
              <button
                type="button"
                className="btn-secondary"
                onClick={() => setShowForm(false)}
              >
                ✕ Hủy
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="storekeeper-imports__filters">
        <form onSubmit={handleFilterSubmit} className="storekeeper-imports__filter-form">
          <div className="storekeeper-imports__filter-row">
            <div className="form-group">
              <label>Sản phẩm</label>
              <select
                name="productId"
                value={filters.productId}
                onChange={handleFilterChange}
                className="form-input"
              >
                <option value="">-- Tất cả sản phẩm --</option>
                {products.map(p => (
                  <option key={p.product_id} value={p.product_id}>
                    {p.product_code} - {p.product_name}
                  </option>
                ))}
              </select>
            </div>

            <div className="form-group">
              <label>Từ Ngày</label>
              <input
                type="date"
                name="startDate"
                value={filters.startDate}
                onChange={handleFilterChange}
                className="form-input"
              />
            </div>

            <div className="form-group">
              <label>Đến Ngày</label>
              <input
                type="date"
                name="endDate"
                value={filters.endDate}
                onChange={handleFilterChange}
                className="form-input"
              />
            </div>

            <button type="submit" className="btn-secondary">
              🔍 Lọc
            </button>
          </div>
        </form>
      </div>

      <div className="storekeeper-imports__table-container">
        <table className="storekeeper-imports__table">
          <thead>
            <tr>
              <th>Ngày Nhập</th>
              <th>Mã Sản Phẩm</th>
              <th>Tên Sản Phẩm</th>
              <th>Số Lượng</th>
              <th>Đơn Vị</th>
              <th>Đơn Giá</th>
              <th>Thành Tiền</th>
              <th>Người Nhập</th>
              <th>Ghi Chú</th>
            </tr>
          </thead>
          <tbody>
            {imports.length === 0 ? (
              <tr>
                <td colSpan="9" className="text-center">
                  Không có dữ liệu nhập kho
                </td>
              </tr>
            ) : (
              imports.map(imp => (
                <tr key={imp.import_id}>
                  <td>{new Date(imp.import_date).toLocaleDateString('vi-VN')}</td>
                  <td className="font-mono">{imp.product_code}</td>
                  <td>{imp.product_name}</td>
                  <td className="text-right">{imp.quantity.toLocaleString('vi-VN', { maxFractionDigits: 2 })}</td>
                  <td>{imp.unit}</td>
                  <td className="text-right">{imp.unit_price.toLocaleString('vi-VN', { maxFractionDigits: 0 })} ₫</td>
                  <td className="text-right font-bold">{imp.total_amount.toLocaleString('vi-VN', { maxFractionDigits: 0 })} ₫</td>
                  <td>{imp.created_by_name || 'N/A'}</td>
                  <td className="text-muted">{imp.note || '-'}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default StorekeeperImports;
